import{c as e,Q as r,j as l,m as d}from"./chunks/framework.rlpw0eGz.js";const y=JSON.parse('{"title":"Compatibility Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"Compatibility_Matrix.md","filePath":"Compatibility_Matrix.md"}'),n={name:"Compatibility_Matrix.md"};function a(i,t,s,o,p,g){return r(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="compatibility-matrix" tabindex="-1">Compatibility Matrix <a class="header-anchor" href="#compatibility-matrix" aria-label="Permalink to &quot;Compatibility Matrix&quot;">​</a></h1><p>The Windows-Optimisations framework is designed to be OS-aware. However, as Microsoft introduces and deprecates features across different builds of Windows 10 and Windows 11, certain tweaks may behave differently or become obsolete.</p><p>This matrix tracks the tested compatibility of major module packs across the most common Windows versions as of <strong>Q2 2026</strong>.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Module Pack</th><th style="text-align:center;">Windows 10 (22H2)</th><th style="text-align:center;">Windows 11 (23H2)</th><th style="text-align:center;">Windows 11 (24H2)</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>WPF Dashboard UI</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;">Requires .NET Framework 4.8+ (native on these builds) and PowerShell 5.1+.</td></tr><tr><td style="text-align:left;"><strong>Shell (Copilot/Widgets)</strong></td><td style="text-align:center;">⚠️ Partial</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;">Win10 lacks Copilot &amp; Widgets in the same implementation as Win11. Scripts will safely bypass missing keys.</td></tr><tr><td style="text-align:left;"><strong>Explorer Productivity</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;">Win11 requires specific registry overrides to restore the Classic Context Menu.</td></tr><tr><td style="text-align:left;"><strong>Visual Effects</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Search &amp; Indexing</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Power &amp; Thermal</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Clipboard Privacy</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Sync Isolation</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Camera Privacy</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">⚠️ Partial</td><td style="text-align:left;">Win11 24H2 introduces Copilot+ Studio Effects which may override legacy app access controls.</td></tr><tr><td style="text-align:left;"><strong>GPU &amp; Hardware</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;">HAGS (Hardware Accelerated GPU Scheduling) is recommended for both.</td></tr><tr><td style="text-align:left;"><strong>Scheduled Tasks</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Background Services</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"><code>DiagTrack</code> exists across all versions.</td></tr><tr><td style="text-align:left;"><strong>Updates Control</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Diagnostics (Telemetry)</strong></td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>Apps Debloat</strong></td><td style="text-align:center;">⚠️ Partial</td><td style="text-align:center;">✅ Supported</td><td style="text-align:center;">✅ Supported</td><td style="text-align:left;">Some sponsored apps (e.g., TikTok) are only provisioned out-of-the-box on Windows 11.</td></tr></tbody></table><h3 id="legend" tabindex="-1">Legend <a class="header-anchor" href="#legend" aria-label="Permalink to &quot;Legend&quot;">​</a></h3><ul><li>✅ <strong>Supported</strong>: Fully tested and functional.</li><li>⚠️ <strong>Partial</strong>: Script will run without errors, but the target feature may not exist on this OS, or newer OS features may slightly bypass the legacy block.</li><li>❌ <strong>Unsupported</strong>: Script will fail or cause instability. (Currently, no core modules are unsupported).</li></ul><h3 id="core-engine-note" tabindex="-1">Core Engine Note <a class="header-anchor" href="#core-engine-note" aria-label="Permalink to &quot;Core Engine Note&quot;">​</a></h3><p>The <strong>Core/Restore/</strong> framework is fully functional across Windows PowerShell 5.1 and PowerShell 7+ on both Windows 10 and Windows 11.</p>',8)])])}const x=e(n,[["render",a]]);export{y as __pageData,x as default};
